#include <iostream>
#include <cstdlib>
#include <ctime>

using namespace std;

int main()
{
    srand(time(0));

    const int SIZE = 10;
    int numbers[SIZE];

    cout << "Random Numbers: ";

    for (int i = 0; i < SIZE; i++)
    {
        numbers[i] = rand() % 100 + 1; // 1 to 100
        cout << numbers[i] << " ";
    }

    int largest = numbers[0];
    int smallest = numbers[0];

    for (int i = 1; i < SIZE; i++)
    {
        if (numbers[i] > largest)
            largest = numbers[i];

        if (numbers[i] < smallest)
            smallest = numbers[i];
    }

    cout << "\n\nLargest Number: " << largest;
    cout << "\nSmallest Number: " << smallest << endl;

    return 0;
}

