// Include the iostream library for input/output operations
#include <iostream>
// Include the cstdlib library for standard general-purpose functions
#include <cstdlib>
// Include the ctime library for time-related functions
#include <ctime>

// Use the standard namespace to avoid prefixing standard library elements
using namespace std;

// Define the main function where program execution begins
int main()
{
    // Seed the random number generator with the current time
    srand(time(0));

    // Define a constant integer variable to store the size of the array
    const int SIZE = 10;
    // Declare an integer array of size 'SIZE' to store random numbers
    int numbers[SIZE];

    // Print a message to indicate the start of random number generation
    cout << "Random Numbers: ";

    // Use a for loop to generate and store 'SIZE' number of random numbers
    for (int i = 0; i < SIZE; i++)
    {
        // Generate a random number between 1 and 100 and store it in the array
        numbers[i] = rand() % 100 + 1; // 1 to 100
        // Print the generated random number
        cout << numbers[i] << " ";
    }

    // Initialize variables to store the largest and smallest numbers with the first array element
    int largest = numbers[0];
    int smallest = numbers[0];

    // Use a for loop to iterate through the array and find the largest and smallest numbers
    for (int i = 1; i < SIZE; i++)
    {
        // Check if the current number is larger than the largest number found so far
        if (numbers[i] > largest)
            // Update the largest number if the current number is larger
            largest = numbers[i];

        // Check if the current number is smaller than the smallest number found so far
        if (numbers[i] < smallest)
            // Update the smallest number if the current number is smaller
            smallest = numbers[i];
    }

    // Print the largest number found in the array
    cout << "\n\nLargest Number: " << largest;
    // Print the smallest number found in the array
    cout << "\nSmallest Number: " << smallest << endl;

    // Return 0 to indicate successful program execution
    return 0;
}
